=Generate social captions for this media file.

File name: {{ $json.fileName }}
Mime type: {{ $json.mimeType }}

Instructions:
- Keep every caption short and warm, one or two sentences max
- Write like a coach sharing a moment from the gym, not an advertisement
- Make the wording fresh and not repetitive
- Avoid reusing these recent Instagram hashtags if possible: {{ $json.recentInstagramHashtags || "" }}
- Avoid reusing these recent TikTok hashtags if possible: {{ $json.recentTikTokHashtags || "" }}
- Avoid reusing these recent X hashtags if possible: {{ $json.recentTwitterHashtags || "" }}
- Return ONLY valid JSON

parameters.jsCode:
const item = $input.first().json;
const timeZone = 'America/Chicago';

function getLocalParts(date, timeZone) {
  const fmt = new Intl.DateTimeFormat('en-US', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    weekday: 'short',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
  });

  const parts = {};
  for (const part of fmt.formatToParts(date)) {
    if (part.type !== 'literal') {
      parts[part.type] = part.value;
    }
  }
  return parts;
}

function getTimeZoneOffsetMs(date, timeZone) {
  const p = getLocalParts(date, timeZone);
  const utcLike = Date.UTC(
    Number(p.year),
    Number(p.month) - 1,
    Number(p.day),
    Number(p.hour),
    Number(p.minute),
    Number(p.second)
  );
  return utcLike - date.getTime();
}

function makeZonedDate(year, month, day, hour, minute, timeZone) {
  const guess = new Date(Date.UTC(year, month - 1, day, hour, minute, 0));
  const offset = getTimeZoneOffsetMs(guess, timeZone);
  return new Date(guess.getTime() - offset);
}

function randomOffsetMinutes(maxOffset) {
  return Math.floor(Math.random() * (maxOffset * 2 + 1)) - maxOffset;
}

function addMinutes(isoString, minutes) {
  const d = new Date(isoString);
  d.setMinutes(d.getMinutes() + minutes);
  return d.toISOString();
}

function nextSlot(daysAllowed, hour, minute, timeZone, varianceMinutes = 0) {
  const now = new Date();

  const weekdayMap = {
    Sun: 0,
    Mon: 1,
    Tue: 2,
    Wed: 3,
    Thu: 4,
    Fri: 5,
    Sat: 6,
  };

  for (let i = 0; i < 14; i++) {
    const probe = new Date(now.getTime() + i * 24 * 60 * 60 * 1000);
    const local = getLocalParts(probe, timeZone);

    const dayNum = weekdayMap[local.weekday];
    if (!daysAllowed.includes(dayNum)) continue;

    const offset = randomOffsetMinutes(varianceMinutes);
    const totalMinutes = hour * 60 + minute + offset;
    const adjustedHour = Math.floor(totalMinutes / 60);
    const adjustedMinute = ((totalMinutes % 60) + 60) % 60;

    const candidate = makeZonedDate(
      Number(local.year),
      Number(local.month),
      Number(local.day),
      adjustedHour,
      adjustedMinute,
      timeZone
    );

    if (candidate > now) {
      return candidate.toISOString();
    }
  }

  throw new Error('Could not find next valid schedule slot');
}

const now = new Date();
const localNow = getLocalParts(now, timeZone);
const triggerHour = Number(localNow.hour);

const isMorningRun = triggerHour < 12;

let schedule_tiktok;
let schedule_twitter;
let schedule_instagram;

if (isMorningRun) {
  schedule_tiktok = nextSlot([0,1,2,3,4,5,6], 17, 30, timeZone, 35);
  schedule_twitter = nextSlot([0,1,2,3,4,5,6], 9, 15, timeZone, 20);
  schedule_instagram = nextSlot([0,1,2,3,4,5,6], 12, 30, timeZone, 30);
} else {
  schedule_tiktok = nextSlot([0,1,2,3,4,5,6], 21, 0, timeZone, 30);
  schedule_twitter = nextSlot([0,1,2,3,4,5,6], 18, 30, timeZone, 20);
  schedule_instagram = nextSlot([0,1,2,3,4,5,6], 19, 15, timeZone, 25);
}

return [{
  json: {
    ...item,
    run_type: isMorningRun ? 'morning' : 'afternoon',
    schedule_tiktok,
    schedule_twitter,
    schedule_instagram,
    schedule_instagram_1: schedule_instagram,
    schedule_instagram_2: addMinutes(schedule_instagram, 7),
    schedule_instagram_3: addMinutes(schedule_instagram, 14),
    schedule_instagram_4: addMinutes(schedule_instagram, 21),
    schedule_instagram_5: addMinutes(schedule_instagram, 28),
  }
}];

