const aiOutput = $input.first().json;

let rawText =
  aiOutput.output?.[0]?.content?.[0]?.text ??
  aiOutput.output?.text ??
  aiOutput.text ??
  '';

if (typeof rawText === 'string') {
  rawText = rawText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
}

let parsed;

try {
  parsed = typeof rawText === 'string' ? JSON.parse(rawText) : rawText;
} catch (error) {
  throw new Error(`Failed to parse AI output as JSON: ${rawText}`);
}

const videoData = $('Edit Fields Video').first().json;

return [{
  json: {
    ...videoData,
    instagram_caption: parsed.instagram_caption || "",
    twitter_caption: parsed.twitter_caption || "",
    tiktok_caption: parsed.tiktok_caption || "",
    instagram_hashtags: Array.isArray(parsed.instagram_hashtags) ? parsed.instagram_hashtags : [],
    twitter_hashtags: Array.isArray(parsed.twitter_hashtags) ? parsed.twitter_hashtags : [],
    tiktok_hashtags: Array.isArray(parsed.tiktok_hashtags) ? parsed.tiktok_hashtags : []
  }
}];

const allMedia = $input.all();

if (allMedia.length === 0) {
  throw new Error("No media files found in your Google Drive folder");
}

const sortedMedia = [...allMedia].sort((a, b) => {
  const nameA = (a.json.name || '').trim();
  const nameB = (b.json.name || '').trim();
  return nameA.localeCompare(nameB, undefined, { numeric: true, sensitivity: 'base' });
});

const globalData = $getWorkflowStaticData('global');

if (globalData.currentIndex === undefined) {
  globalData.currentIndex = 0;
}

if (globalData.currentIndex >= sortedMedia.length) {
  globalData.currentIndex = 0;
}

const selected = sortedMedia[globalData.currentIndex].json;

globalData.currentIndex += 1;

return [{
  json: {
    fileId: selected.id,
    fileName: selected.name,
    mimeType: selected.mimeType || "video/mp4"
  }
}];

